import React, { useState, useContext, Suspense } from 'react';
import {
    Box,
    Button,
    Stack,
    TextField,
    ToggleButton,
    ToggleButtonGroup,
    Typography,
    InputBase,
    Paper,
} from '@mui/material';
import EmailOutlinedIcon from '@mui/icons-material/EmailOutlined';
import PhoneIphoneIcon from '@mui/icons-material/PhoneIphone';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import RefreshIcon from '@mui/icons-material/Refresh';
import { EnvConfig } from '@/constants/EnvConfig';
import { useNavigate, useSearch } from '@tanstack/react-router';
import { CallStatus, Validator } from '@/types/api.types';
import { SetAccessTokenData } from '@/utils/token';
import { AuthContext } from '@/contexts/AuthContext';
import { AuthTokenResult, CreateOtpPayload, CreateTokenPayload } from '@/types/auth.types';
import { Pathname } from '@/constants/Routes';
import { AuthServices, AuthServicesError } from '@/api';
import { initialStateData, StateData } from '@/store';
import { StatusMessage } from '@/components/StatusMessage';
import { ApiComponentStateManager } from '@/lib/api-state';
import { InstallAppButton } from '@/components/InstallAppButton';

const OTP_RESEND_COOLDOWN_SECONDS = 30;
const OTP_LENGTH = 6;

type LoginMethod = 'email' | 'authenticator';
type LoginStep = 'identify' | 'verify';

/**
 * Six individual single-character inputs for the OTP code, with auto-advance
 * on type, backspace handling, and paste support.
 */
const OtpInputBoxes: React.FC<{
    value: string;
    onChange: (next: string) => void;
    autoFocus?: boolean;
    disabled?: boolean;
}> = ({ value, onChange, autoFocus, disabled }) => {
    const refs = React.useRef<Array<HTMLInputElement | null>>([]);

    React.useEffect(() => {
        if (autoFocus) refs.current[0]?.focus();
    }, [autoFocus]);

    const setDigit = (index: number, digit: string) => {
        const sanitized = digit.replace(/\D/g, '');
        if (!sanitized) {
            const arr = value.padEnd(OTP_LENGTH, ' ').split('');
            arr[index] = '';
            onChange(arr.join('').replace(/\s+/g, ''));
            return;
        }
        const ch = sanitized[0];
        const arr = value.padEnd(OTP_LENGTH, ' ').split('');
        arr[index] = ch;
        const next = arr.join('').replace(/\s+/g, '').substring(0, OTP_LENGTH);
        onChange(next);
        if (index < OTP_LENGTH - 1) refs.current[index + 1]?.focus();
    };

    const handleKeyDown = (index: number) => (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Backspace') {
            const arr = value.padEnd(OTP_LENGTH, ' ').split('');
            if (arr[index] && arr[index] !== ' ') {
                arr[index] = '';
                onChange(arr.join('').replace(/\s+/g, ''));
            } else if (index > 0) {
                refs.current[index - 1]?.focus();
                arr[index - 1] = '';
                onChange(arr.join('').replace(/\s+/g, ''));
            }
        } else if (e.key === 'ArrowLeft' && index > 0) {
            refs.current[index - 1]?.focus();
        } else if (e.key === 'ArrowRight' && index < OTP_LENGTH - 1) {
            refs.current[index + 1]?.focus();
        }
    };

    const handlePaste = (e: React.ClipboardEvent<HTMLInputElement>) => {
        e.preventDefault();
        const pasted = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, OTP_LENGTH);
        if (pasted) {
            onChange(pasted);
            const focusIndex = Math.min(pasted.length, OTP_LENGTH - 1);
            refs.current[focusIndex]?.focus();
        }
    };

    return (
        <Stack direction='row' spacing={1.25} sx={{ justifyContent: 'center' }}>
            {Array.from({ length: OTP_LENGTH }).map((_, i) => (
                <Paper
                    key={i}
                    elevation={0}
                    variant='outlined'
                    sx={{
                        width: 38,
                        height: 46,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        borderRadius: 2,
                        borderColor: value[i] ? 'primary.main' : 'divider',
                        bgcolor: 'background.paper',
                    }}
                >
                    <InputBase
                        inputRef={(el: HTMLInputElement | null) => { refs.current[i] = el; }}
                        value={value[i] ?? ''}
                        onChange={(e) => setDigit(i, e.target.value)}
                        onKeyDown={handleKeyDown(i)}
                        onPaste={handlePaste}
                        inputProps={{
                            inputMode: 'numeric',
                            pattern: '[0-9]*',
                            maxLength: 1,
                            'aria-label': `Digit ${i + 1}`,
                            style: {
                                textAlign: 'center',
                                fontSize: '1.25rem',
                                fontWeight: 600,
                                padding: 0,
                            },
                        }}
                        disabled={disabled}
                        sx={{ width: '100%', height: '100%' }}
                    />
                </Paper>
            ))}
        </Stack>
    );
};

const LoginContent: React.FC = () => {
    const { setAuthData } = useContext(AuthContext);
    const [sendOtp, setSendOtp] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [requestToken, setRequestToken] = React.useState<StateData<AuthTokenResult>>(initialStateData<AuthTokenResult>());
    const [method, setMethod] = useState<LoginMethod>('email');
    const [step, setStep] = useState<LoginStep>('identify');
    const [formData, setFormData] = useState<CreateTokenPayload>({ emailOrPhone: '', otp: '' });
    const [redirectUrl, setRedirectUrl] = useState<string>(Pathname.Root);
    const [isRedirecting, setIsRedirecting] = useState(false);
    const [resendCooldown, setResendCooldown] = useState<number>(0);

    const navigate = useNavigate();
    const search = useSearch({ strict: false }) as Record<string, string>;

    React.useEffect(() => {
        const redirect = search?.redirect || Pathname.Root;
        setRedirectUrl(redirect);
    }, [search]);

    React.useEffect(() => {
        if (requestToken.status === CallStatus.Success && requestToken.data.accessToken) {
            SetAccessTokenData(requestToken.data);
            setAuthData({ name: requestToken.data.name, email: requestToken.data.resource });
            setIsRedirecting(true);
            window.dispatchEvent(new Event('auth-changed'));
            if (!requestToken.data.xv) {
                navigate({
                    to: Pathname.Profile_Edit as string,
                    search: { redirect: redirectUrl },
                    replace: true,
                });
            } else {
                navigate({ to: redirectUrl, replace: true });
            }
        }
    }, [requestToken.status, redirectUrl, navigate, setAuthData, requestToken.data]);

    React.useEffect(() => {
        if (sendOtp.status === CallStatus.Success || sendOtp.status === CallStatus.Failure) {
            setResendCooldown(OTP_RESEND_COOLDOWN_SECONDS);
            // Clear any stale verify error so only the latest alert shows.
            setRequestToken(initialStateData<AuthTokenResult>());
        }
    }, [sendOtp.status]);

    // Verify-call lifecycle: drop any stale send-OTP message so the user
    // only sees the most recent alert (e.g. "Incorrect login credentials"),
    // not a green "OTP sent" banner stacked above it.
    React.useEffect(() => {
        if (
            requestToken.status === CallStatus.InProgress ||
            requestToken.status === CallStatus.Failure
        ) {
            setSendOtp(initialStateData<boolean>());
        }
    }, [requestToken.status]);

    React.useEffect(() => {
        if (resendCooldown <= 0) return;
        const id = window.setInterval(() => {
            setResendCooldown((prev) => (prev <= 1 ? 0 : prev - 1));
        }, 1000);
        return () => window.clearInterval(id);
    }, [resendCooldown]);

    if (isRedirecting) return null;

    const emailValid = Validator.IsEmail(formData.emailOrPhone);
    const otpValid = formData.otp.length === OTP_LENGTH && Validator.IsNumber(formData.otp);

    const requestEmailOtp = () => {
        if (!emailValid || resendCooldown > 0) return;
        const payload: CreateOtpPayload = { emailOrPhone: formData.emailOrPhone };
        ApiComponentStateManager(AuthServices.CreateOtp(payload), setSendOtp);
    };

    const handleSendVerification = () => {
        if (!emailValid) return;
        if (method === 'email') {
            requestEmailOtp();
        }
        setStep('verify');
    };

    const handleVerify = () => {
        if (!emailValid || !otpValid) return;
        const payload: CreateTokenPayload = {
            emailOrPhone: formData.emailOrPhone,
            otp: formData.otp,
        };
        ApiComponentStateManager(AuthServices.CreateToken(payload), setRequestToken);
    };

    const handleBack = () => {
        setStep('identify');
        setFormData((prev) => ({ ...prev, otp: '' }));
        setRequestToken(initialStateData<AuthTokenResult>());
    };

    const handleMethodChange = (_: React.MouseEvent<HTMLElement>, next: LoginMethod | null) => {
        if (!next) return;
        setMethod(next);
        setFormData((prev) => ({ ...prev, otp: '' }));
        setSendOtp(initialStateData<boolean>());
    };

    return (
        <Box
            sx={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                // Use dvh and account for topbar (56) + main margin top + site footer area.
                // Subtract a bit MORE on mobile to remove residual scroll.
                minHeight: { xs: 'calc(100dvh - 220px)', sm: 'calc(100dvh - 160px)' },
                // Slight upward bias: extra padding on the bottom centers the card
                // a little above the geometric middle.
                pt: { xs: '40px', sm: 0 },
                pb: { xs: '0px', sm: '40px' },
                px: 2,
                width: '100%',
            }}
        >
            <Paper
                elevation={2}
                sx={{
                    width: '100%',
                    maxWidth: 300,
                    height: { xs: 360, sm: 380 },
                    p: { xs: 2, sm: 2.5 },
                    borderRadius: 3,
                    bgcolor: 'background.paper',
                    display: 'flex',
                    flexDirection: 'column',
                }}
            >
                <Stack direction='row' spacing={1.5} sx={{ alignItems: 'center', justifyContent: 'center', mb: 2, ml: '-10px' }}>
                    {EnvConfig.SiteLogo && (
                        <Box
                            component='img'
                            src={EnvConfig.SiteLogo}
                            alt={`${EnvConfig.SiteName} logo`}
                            sx={{ width: 48, height: 48, borderRadius: 2, objectFit: 'contain', flexShrink: 0 }}
                        />
                    )}
                    <Box sx={{ minWidth: 0 }}>
                        <Typography variant='h6' sx={{ fontWeight: 700, lineHeight: 1.2 }}>
                            Welcome back
                        </Typography>
                        <Typography variant='caption' color='text.secondary' sx={{ display: 'block', lineHeight: 1.3 }}>
                            Sign in to your account
                        </Typography>
                    </Box>
                </Stack>

                <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column', minHeight: 0 }}>
                    {step === 'identify' ? (
                        <IdentifyStep
                            method={method}
                            emailValid={emailValid}
                            formData={formData}
                            sendOtpStatus={sendOtp.status}
                            onMethodChange={handleMethodChange}
                            onEmailChange={(v) => setFormData((prev) => ({ ...prev, emailOrPhone: v }))}
                            onSubmit={handleSendVerification}
                        />
                    ) : (
                        <VerifyStep
                            method={method}
                            email={formData.emailOrPhone}
                            otp={formData.otp}
                            onOtpChange={(v) => setFormData((prev) => ({ ...prev, otp: v }))}
                            onBack={handleBack}
                            onVerify={handleVerify}
                            onResend={requestEmailOtp}
                            resendCooldown={resendCooldown}
                            verifying={requestToken.status === CallStatus.InProgress}
                            sendingOtp={sendOtp.status === CallStatus.InProgress}
                            otpValid={otpValid}
                        />
                    )}
                </Box>

                <Footer />
            </Paper>

            {/* Reserved slot below the card so its position stays fixed
                whether or not a status message is showing. */}
            <Box
                sx={{
                    width: '100%',
                    maxWidth: 300,
                    mt: 1.5,
                    minHeight: 56,
                }}
            >
                {step === 'verify' && (
                    requestToken.status !== CallStatus.NotStarted &&
                    requestToken.status !== CallStatus.Success ? (
                        <StatusMessage
                            style={{ paddingTop: 4, paddingBottom: 4 }}
                            failureMessage={AuthServicesError.CreateTokenError(requestToken.httpStatus)}
                            currentStatus={requestToken.status}
                        />
                    ) : (
                        method === 'email' && sendOtp.status !== CallStatus.NotStarted && (
                            <StatusMessage
                                style={{ paddingTop: 4, paddingBottom: 4 }}
                                successMessage='OTP sent to your email.'
                                failureMessage={AuthServicesError.CreateOtpError(sendOtp.httpStatus)}
                                inProgressMessage='Sending OTP...'
                                currentStatus={sendOtp.status}
                            />
                        )
                    )
                )}
            </Box>
        </Box>
    );
};

const IdentifyStep: React.FC<{
    method: LoginMethod;
    emailValid: boolean;
    formData: CreateTokenPayload;
    sendOtpStatus: CallStatus;
    onMethodChange: (e: React.MouseEvent<HTMLElement>, next: LoginMethod | null) => void;
    onEmailChange: (value: string) => void;
    onSubmit: () => void;
}> = ({ method, emailValid, formData, sendOtpStatus, onMethodChange, onEmailChange, onSubmit }) => (
    <form
        onSubmit={(e) => {
            e.preventDefault();
            onSubmit();
        }}
    >
        <Stack spacing={1.5}>
            <ToggleButtonGroup
                value={method}
                exclusive
                onChange={onMethodChange}
                fullWidth
                sx={{
                    borderRadius: 2,
                    bgcolor: 'action.hover',
                    p: 0.5,
                    '& .MuiToggleButton-root': {
                        border: 0,
                        borderRadius: 1.5,
                        textTransform: 'none',
                        fontWeight: 600,
                        gap: 1,
                        py: 1,
                        color: 'text.secondary',
                        '&.Mui-selected': {
                            bgcolor: 'background.paper',
                            color: 'primary.main',
                            boxShadow: 1,
                            '&:hover': { bgcolor: 'background.paper' },
                        },
                    },
                }}
            >
                <ToggleButton value='email'>
                    <EmailOutlinedIcon fontSize='small' />
                    Email OTP
                </ToggleButton>
                <ToggleButton value='authenticator'>
                    <PhoneIphoneIcon fontSize='small' />
                    Authenticator
                </ToggleButton>
            </ToggleButtonGroup>

            <TextField
                id='email'
                label='Email address'
                variant='outlined'
                fullWidth
                value={formData.emailOrPhone}
                required
                inputMode='email'
                autoComplete='email'
                onChange={(e) => onEmailChange(e.target.value)}
                error={formData.emailOrPhone !== '' && !emailValid}
            />

            <Button
                type='submit'
                variant='contained'
                fullWidth
                disabled={!emailValid || sendOtpStatus === CallStatus.InProgress}
                sx={{
                    py: 1,
                    borderRadius: 2,
                    fontWeight: 700,
                    textTransform: 'none',
                    fontSize: '0.9rem',
                }}
            >
                {method === 'email' ? 'Send verification code' : 'Continue'}
            </Button>
        </Stack>
    </form>
);

const VerifyStep: React.FC<{
    method: LoginMethod;
    email: string;
    otp: string;
    otpValid: boolean;
    verifying: boolean;
    sendingOtp: boolean;
    resendCooldown: number;
    onOtpChange: (value: string) => void;
    onBack: () => void;
    onVerify: () => void;
    onResend: () => void;
}> = ({
    method,
    email,
    otp,
    otpValid,
    verifying,
    sendingOtp,
    resendCooldown,
    onOtpChange,
    onBack,
    onVerify,
    onResend,
}) => (
    <form
        onSubmit={(e) => {
            e.preventDefault();
            onVerify();
        }}
    >
        <Stack spacing={1.5}>
            <Typography variant='body2' color='text.secondary' sx={{ textAlign: 'center' }}>
                {method === 'email' ? (
                    <>
                        We sent a 6-digit code to{' '}
                        <Box component='span' sx={{ color: 'primary.main', fontWeight: 600 }}>
                            {email}
                        </Box>
                        . It expires in 5 minutes.
                    </>
                ) : (
                    <>
                        Open your authenticator app and enter the current code for{' '}
                        <Box component='span' sx={{ color: 'primary.main', fontWeight: 600 }}>
                            {email}
                        </Box>
                        .
                    </>
                )}
            </Typography>

            <OtpInputBoxes value={otp} onChange={onOtpChange} autoFocus disabled={verifying} />

            <Stack direction='row' spacing={1.5} sx={{ justifyContent: 'center' }}>
                <Button
                    type='button'
                    variant='outlined'
                    color='primary'
                    startIcon={<ArrowBackIcon sx={{ color: 'primary.main' }} />}
                    onClick={onBack}
                    sx={{
                        textTransform: 'none',
                        borderRadius: 2,
                        px: 2,
                        py: 0.75,
                        fontSize: '0.875rem',
                        color: 'primary.main',
                    }}
                >
                    Back
                </Button>
                {otp.length === 0 && method === 'email' ? (
                    <Button
                        type='button'
                        variant='contained'
                        onClick={onResend}
                        disabled={resendCooldown > 0 || sendingOtp}
                        startIcon={<RefreshIcon fontSize='small' sx={{ color: '#fff' }} />}
                        sx={{
                            textTransform: 'none',
                            fontWeight: 700,
                            borderRadius: 2,
                            px: 2.5,
                            py: 0.75,
                            fontSize: '0.875rem',
                            flexGrow: 1,
                            maxWidth: 220,
                            whiteSpace: 'nowrap',
                        }}
                    >
                        {resendCooldown > 0
                            ? `Resend in ${resendCooldown}s`
                            : 'Resend code'}
                    </Button>
                ) : (
                    <Button
                        type='submit'
                        variant='contained'
                        disabled={!otpValid || verifying}
                        sx={{
                            textTransform: 'none',
                            fontWeight: 700,
                            borderRadius: 2,
                            px: 2.5,
                            py: 0.75,
                            fontSize: '0.875rem',
                            flexGrow: 1,
                            maxWidth: 220,
                            whiteSpace: 'nowrap',
                        }}
                    >
                        {verifying ? 'Verifying…' : 'Verify & sign in'}
                    </Button>
                )}
            </Stack>
        </Stack>
    </form>
);

const Footer: React.FC = () => (
    <Stack spacing={1} sx={{ mt: 2, alignItems: 'center', textAlign: 'center' }}>
        <Typography variant='caption' color='text.secondary' sx={{ maxWidth: 320 }}>
            By continuing you agree to {EnvConfig.SiteName}'s terms of service and privacy policy.
        </Typography>
        <InstallAppButton />
    </Stack>
);

export const Login: React.FC = () => (
    <Suspense fallback={<Box sx={{ display: 'flex', justifyContent: 'center', p: 2.5 }}>Loading...</Box>}>
        <LoginContent />
    </Suspense>
);
